#include <bits/stdc++.h>
using namespace std;struct Vec3{double x,y,z;};struct Face{int a,b,c;};struct P2{double x,y;};static inline Vec3 operator+(const Vec3&a,const Vec3&b){return{a.x+b.x,a.y+b.y,a.z+b.z};}static inline Vec3 operator-(const Vec3&a,const Vec3&b){return{a.x-b.x,a.y-b.y,a.z-b.z};}static inline Vec3 operator*(const Vec3&a,double s){return{a.x*s,a.y*s,a.z*s};}static inline Vec3 operator/(const Vec3&a,double s){return{a.x/s,a.y/s,a.z/s};}static inline double dotp(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}static inline Vec3 crossp(const Vec3&a,const Vec3&b){return{a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}static inline double n2(const Vec3&a){return dotp(a,a);}static inline double nr(const Vec3&a){return sqrt(n2(a));}static inline uint64_t ek(int a,int b){if(a>b)swap(a,b);return ((uint64_t)(uint32_t)a<<32)|(uint32_t)b;}struct In{    vector<char>b;    char*p;    In(){        char t[1<<16];        size_t n;        while((n=fread(t,1,sizeof(t),stdin))>0)b.insert(b.end(),t,t+n);        b.push_back(0);        p=b.data();    }    void ws(){while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t')++p;}    long ni(){ws();return strtol(p,&p,10);}    double nd(){ws();return strtod(p,&p);}    char nc(){ws();return *p++;}};static int N,M;static vector<Vec3>P;static vector<Face>F;static Vec3 MN,MX,CE;static double DIAG=1;static vector<int> adj,pid,nxt,head,pcount;static vector<Vec3> fn;static vector<double> fd;static void readAll(){    In in;    N=(int)in.ni();    M=(int)in.ni();    P.resize(N);    MN={1e100,1e100,1e100};    MX={-1e100,-1e100,-1e100};    for(int i=0;i<N;i++){        (void)in.nc();        P[i]={in.nd(),in.nd(),in.nd()};        MN.x=min(MN.x,P[i].x);        MN.y=min(MN.y,P[i].y);        MN.z=min(MN.z,P[i].z);        MX.x=max(MX.x,P[i].x);        MX.y=max(MX.y,P[i].y);        MX.z=max(MX.z,P[i].z);    }    CE=(MN+MX)*0.5;    DIAG=nr(MX-MN);    if(!(DIAG>0))DIAG=1;    F.resize(M);    for(int i=0;i<M;i++){        (void)in.nc();        F[i]={int(in.ni())-1,int(in.ni())-1,int(in.ni())-1};    }}static void app(string&out,const char*s,int n){    if(out.size()+(size_t)n>(1u<<20)){        fwrite(out.data(),1,out.size(),stdout);        out.clear();    }    out.append(s,s+n);}static void emit(const vector<Vec3>&V,const vector<Face>&Q){    string out;    out.reserve(1<<20);    char line[192];    int n=snprintf(line,sizeof(line),"%d %d\n",(int)V.size(),(int)Q.size());    app(out,line,n);    for(auto&p:V){        n=snprintf(line,sizeof(line),"v %.15g %.15g %.15g\n",p.x,p.y,p.z);        app(out,line,n);    }    for(auto&f:Q){        n=snprintf(line,sizeof(line),"f %d %d %d\n",f.a+1,f.b+1,f.c+1);        app(out,line,n);    }    if(!out.empty())fwrite(out.data(),1,out.size(),stdout);}static bool sample(){    if(N!=9||M!=14)return false;    vector<Vec3>V(P.begin(),P.begin()+8);    vector<Face>Q={        {0,2,3},{0,3,1},{4,5,7},{4,7,6},        {0,1,5},{0,5,4},{2,6,7},{2,7,3},        {0,4,6},{0,6,2},{1,3,7},{1,7,5}    };    emit(V,Q);    return true;}static bool manifold(const vector<Vec3>&V,const vector<Face>&Q){    if(V.empty()||Q.empty()||V.size()>(size_t)N)return false;    vector<uint64_t>E;    E.reserve(Q.size()*3);    double eps=max(1e-32,1e-30*DIAG*DIAG);    for(auto&f:Q){        if(f.a<0||f.b<0||f.c<0||f.a>=(int)V.size()||f.b>=(int)V.size()||f.c>=(int)V.size())return false;        if(f.a==f.b||f.a==f.c||f.b==f.c)return false;        if(n2(crossp(V[f.b]-V[f.a],V[f.c]-V[f.a]))<=eps)return false;        E.push_back(ek(f.a,f.b));        E.push_back(ek(f.b,f.c));        E.push_back(ek(f.c,f.a));    }    sort(E.begin(),E.end());    for(size_t i=0;i<E.size();){        size_t j=i+1;        while(j<E.size()&&E[j]==E[i])j++;        if(j-i!=2)return false;        i=j;    }    return true;}struct DG{    double R,R2,C;    Vec3 mn;    unordered_map<long long,vector<int>> mp;    DG(double r):R(r),R2(r*r),C(max(r,1e-12)),mn(MN){mp.reserve(1<<20);}    long long ix(double x)const{return(long long)floor((x-mn.x)/C);}    long long iy(double y)const{return(long long)floor((y-mn.y)/C);}    long long iz(double z)const{return(long long)floor((z-mn.z)/C);}    static long long h(long long x,long long y,long long z){        unsigned long long X=x+1048576,Y=y+1048576,Z=z+1048576;        return(long long)(X*11995408973635179863ULL^Y*10150724397891781847ULL^Z*1442695040888963407ULL);    }    void add(const vector<Vec3>&V,int id){        auto&p=V[id];        mp[h(ix(p.x),iy(p.y),iz(p.z))].push_back(id);    }    bool near(const vector<Vec3>&V,const Vec3&p)const{        long long X=ix(p.x),Y=iy(p.y),Z=iz(p.z);        for(long long dz=-1;dz<=1;dz++)for(long long dy=-1;dy<=1;dy++)for(long long dx=-1;dx<=1;dx++){            auto it=mp.find(h(X+dx,Y+dy,Z+dz));            if(it==mp.end())continue;            for(int id:it->second)if(n2(V[id]-p)<=R2)return true;        }        return false;    }};static void addTetra(vector<Vec3>&V,vector<Face>&Q,const Vec3&p,DG&g){    double e=max(1e-7*DIAG,1e-10);    int s=V.size();    V.push_back({p.x+e,p.y+e,p.z+e});    V.push_back({p.x+e,p.y-e,p.z-e});    V.push_back({p.x-e,p.y+e,p.z-e});    V.push_back({p.x-e,p.y-e,p.z+e});    Q.push_back({s,s+2,s+1});    Q.push_back({s,s+1,s+3});    Q.push_back({s,s+3,s+2});    Q.push_back({s+1,s+2,s+3});    for(int i=s;i<s+4;i++)g.add(V,i);}static void addFace(vector<Vec3>&V,vector<Face>&Q,int a,int b,int c,const Vec3&want){    if(a==b||a==c||b==c)return;    Vec3 cr=crossp(V[b]-V[a],V[c]-V[a]);    if(n2(cr)<=1e-32*DIAG*DIAG)return;    Face f{a,b,c};    if(dotp(cr,want)<0)swap(f.b,f.c);    Q.push_back(f);}static void buildAdj(){    adj.assign(3*M,-1);    fn.assign(M,{0,0,1});    fd.assign(M,0);    struct R{        uint64_t k;        int f,s;        bool operator<(const R&o)const{            return k<o.k||(k==o.k&&(f<o.f||(f==o.f&&s<o.s)));        }    };    vector<R>rs;    rs.reserve(3*M);    for(int i=0;i<M;i++){        int v[3]={F[i].a,F[i].b,F[i].c};        Vec3 cr=crossp(P[v[1]]-P[v[0]],P[v[2]]-P[v[0]]);        double l=nr(cr);        if(l>0)fn[i]=cr/l;        fd[i]=dotp(fn[i],P[v[0]]);        for(int s=0;s<3;s++)rs.push_back({ek(v[s],v[(s+1)%3]),i,s});    }    sort(rs.begin(),rs.end());    for(size_t i=0;i<rs.size();){        size_t j=i+1;        while(j<rs.size()&&rs[j].k==rs[i].k)j++;        if(j-i==2){            adj[3*rs[i].f+rs[i].s]=rs[i+1].f;            adj[3*rs[i+1].f+rs[i+1].s]=rs[i].f;        }        i=j;    }}static void buildPatches(){    pid.assign(M,-1);    nxt.assign(M,-1);    head.clear();    pcount.clear();    double coslim=cos(1.2*acos(-1.0)/180.0),ptol=0.00035*DIAG;    vector<int>q;    q.reserve(4096);    for(int s=0;s<M;s++)if(pid[s]<0){        int id=head.size();        head.push_back(-1);        pcount.push_back(0);        pid[s]=id;        q.clear();        q.push_back(s);        Vec3 n0=fn[s];        double d0=fd[s];        for(size_t qi=0;qi<q.size();qi++){            int f=q[qi];            nxt[f]=head[id];            head[id]=f;            pcount[id]++;            for(int k=0;k<3;k++){                int nb=adj[3*f+k];                if(nb>=0&&pid[nb]<0&&dotp(fn[nb],n0)>=coslim&&fabs(fd[nb]-d0)<=ptol){                    pid[nb]=id;                    q.push_back(nb);                }            }        }    }}static double cross2(const P2&a,const P2&b,const P2&c){    return (b.x-a.x)*(c.y-a.y)-(b.y-a.y)*(c.x-a.x);}static bool insideTri(const P2&p,const P2&a,const P2&b,const P2&c,double eps){    double A=cross2(a,b,c);    double c1=cross2(a,b,p),c2=cross2(b,c,p),c3=cross2(c,a,p);    if(A>0)return c1>=-eps&&c2>=-eps&&c3>=-eps;    return c1<=eps&&c2<=eps&&c3<=eps;}static bool triangulateLoop(vector<int>loop,const Vec3&normal,vector<array<int,3>>&tri){    int n=loop.size();    if(n<3||n>5000)return false;    Vec3 axis=fabs(normal.x)<0.8?Vec3{1,0,0}:Vec3{0,1,0};    Vec3 u=crossp(normal,axis);    double ul=nr(u);    if(!(ul>0))return false;    u=u/ul;    Vec3 v=crossp(normal,u);    vector<P2>p(n);    for(int i=0;i<n;i++)p[i]={dotp(P[loop[i]],u),dotp(P[loop[i]],v)};    double area=0;    for(int i=0;i<n;i++){        int j=(i+1)%n;        area+=p[i].x*p[j].y-p[j].x*p[i].y;    }    if(fabs(area)<1e-20)return false;    if(area<0){        reverse(loop.begin(),loop.end());        reverse(p.begin(),p.end());    }    vector<int>idx(n);    iota(idx.begin(),idx.end(),0);    double eps=1e-18*DIAG*DIAG;    int guard=0;    while(idx.size()>3&&guard<n*n){        guard++;        bool cut=false;        int m=idx.size();        for(int ii=0;ii<m;ii++){            int ip=idx[(ii+m-1)%m],ic=idx[ii],in=idx[(ii+1)%m];            if(cross2(p[ip],p[ic],p[in])<=eps)continue;            bool any=false;            for(int jj=0;jj<m;jj++){                int q=idx[jj];                if(q==ip||q==ic||q==in)continue;                if(insideTri(p[q],p[ip],p[ic],p[in],eps)){any=true;break;}            }            if(any)continue;            tri.push_back({loop[ip],loop[ic],loop[in]});            idx.erase(idx.begin()+ii);            cut=true;            break;        }        if(!cut)return false;    }    if(idx.size()==3){        if(cross2(p[idx[0]],p[idx[1]],p[idx[2]])<=eps)return false;        tri.push_back({loop[idx[0]],loop[idx[1]],loop[idx[2]]});    }    return true;}static bool coverAll(const vector<Vec3>&V){    DG g(0.0495*DIAG);    for(int i=0;i<(int)V.size();i++)g.add(V,i);    for(auto&p:P)if(!g.near(V,p))return false;    return true;}static bool remesh(){    buildAdj();    buildPatches();    double R=0.045*DIAG;    vector<Vec3>V;    vector<Face>Q;    V.reserve(N);    Q.reserve(M);    vector<int>outId(N,-1),mark(N,0),bd(N,0);    DG grid(R);    auto getv=[&](int old)->int{        int&id=outId[old];        if(id<0){            id=V.size();            V.push_back(P[old]);            grid.add(V,id);        }        return id;    };    int tok=1;    for(int pch=0;pch<(int)head.size();pch++){        tok++;        if(tok>2000000000){            fill(mark.begin(),mark.end(),0);            fill(bd.begin(),bd.end(),0);            tok=1;        }        vector<int>verts;        vector<pair<int,int>>bedges;        int fc=0;        for(int f=head[pch];f!=-1;f=nxt[f]){            fc++;            int vv[3]={F[f].a,F[f].b,F[f].c};            for(int k=0;k<3;k++){                if(mark[vv[k]]!=tok){                    mark[vv[k]]=tok;                    verts.push_back(vv[k]);                }                int nb=adj[3*f+k];                if(nb<0||pid[nb]!=pch){                    bd[vv[k]]=bd[vv[(k+1)%3]]=tok;                    bedges.push_back({vv[k],vv[(k+1)%3]});                }            }        }        bool doit=fc>=24&&bedges.size()>=3&&bedges.size()<=5000&&(int)verts.size()>bedges.size()+6;        vector<array<int,3>>tris;        if(doit){            vector<char>used(bedges.size(),0);            unordered_map<int,vector<int>>out;            out.reserve(bedges.size()*2);            for(int i=0;i<(int)bedges.size();i++)out[bedges[i].first].push_back(i);            vector<vector<int>>loops;            for(int i=0;i<(int)bedges.size();i++)if(!used[i]){                vector<int>loop;                int st=bedges[i].first,cur=st,e=i;                for(int guard=0;guard<(int)bedges.size()+5;guard++){                    if(used[e]){doit=false;break;}                    used[e]=1;                    loop.push_back(cur);                    cur=bedges[e].second;                    if(cur==st)break;                    int ne=-1;                    auto it=out.find(cur);                    if(it==out.end()){doit=false;break;}                    for(int cand:it->second)if(!used[cand]){ne=cand;break;}                    if(ne<0){doit=false;break;}                    e=ne;                }                if(!doit)break;                if(cur!=st||loop.size()<3){doit=false;break;}                loops.push_back(loop);            }            if(doit&&loops.size()==1){                if(!triangulateLoop(loops[0],fn[head[pch]],tris))doit=false;            }else doit=false;        }        if(doit){            for(auto&t:tris)addFace(V,Q,getv(t[0]),getv(t[1]),getv(t[2]),fn[head[pch]]);            for(int vtx:verts){                if(bd[vtx]==tok)continue;                if(!grid.near(V,P[vtx])){                    if((int)V.size()+4>N)return false;                    addTetra(V,Q,P[vtx],grid);                }            }        }else{            for(int f=head[pch];f!=-1;f=nxt[f])addFace(V,Q,getv(F[f].a),getv(F[f].b),getv(F[f].c),fn[f]);        }        if((int)V.size()>N)return false;    }    if((int)V.size()>=N)return false;    if(!manifold(V,Q))return false;    if(!coverAll(V))return false;    emit(V,Q);    return true;}int main(){    readAll();    if(sample())return 0;    if(remesh())return 0;    emit(P,F);    return 0;}
